1	package auth
2	
3	import (
4		"context"
5		"crypto/tls"
6		"encoding/json"
7		"errors"
8		"fmt"
9		"net/http"
10		"net/url"
11		"os"
12		"path/filepath"
13		"strconv"
14		"strings"
15		"time"
16	
17		"github.com/zalando/go-keyring"
18	)
19	
20	func isNotFound(err error) bool {
21		return errors.Is(err, keyring.ErrNotFound)
22	}
23	
24	const entireCLIClientID = "entire-cli"
25	
26	type entireAuthHostInfo struct {
27		ActiveUser string   `json:"activeUser"`
28		Users      []string `json:"users"`
29	}
30	
31	type oauthTokenResponse struct {
32		AccessToken  string `json:"access_token"`
33		RefreshToken string `json:"refresh_token"`
34		ExpiresIn    int64  `json:"expires_in"`
35	}
36	
37	// LookupEntireDBCredential looks up credentials from the Entire token store.
38	// Returns (username, password, true, nil) on success, ("", "", false, nil) when
39	// no credential is configured, or ("", "", false, err) when a credential exists
40	// but refresh failed (issue #7).
41	func LookupEntireDBCredential(raw Endpoint, ep *url.URL) (string, string, bool, error) {
42		if ep == nil || ep.Host == "" {
43			return "", "", false, nil
44		}
45		credHost := endpointCredentialHost(ep)
46		token, err := lookupEntireDBToken(credHost, endpointBaseURL(ep), raw.SkipTLSVerify)
47		if err != nil {
48			return "", "", false, err
49		}
50		if token == "" {
51			return "", "", false, nil
52		}
53		username := raw.Username
54		if username == "" {
55			username = defaultGitUsername
56		}
57		return username, token, true, nil
58	}
59	
60	func endpointBaseURL(ep *url.URL) string {
61		if ep == nil || ep.Hostname() == "" {
62			return ""
63		}
64		scheme := ep.Scheme
65		if scheme == "" {
66			scheme = "https"
67		}
68		host := ep.Host // includes port if present in url.URL
69		return scheme + "://" + host
70	}
71	
72	func endpointCredentialHost(ep *url.URL) string {
73		if ep == nil {
74			return ""
75		}
76		return ep.Host // includes port if present in url.URL
77	}
78	
79	func lookupEntireDBToken(host, baseURL string, skipTLS bool) (string, error) {
80		configDir := os.Getenv("ENTIRE_CONFIG_DIR")
81		if configDir == "" {
82			home, err := os.UserHomeDir()
83			if err != nil {
84				return "", nil //nolint:nilerr // missing config dir means no stored credentials, not an error
85			}
86			configDir = filepath.Join(home, ".config", "entire")
87		}
88	
89		username, ok := loadEntireDBActiveUser(host, configDir)
90		if !ok || username == "" {
91			return "", nil
92		}
93		return getTokenWithRefresh(context.Background(), host, username, baseURL, skipTLS)
94	}
95	
96	func loadEntireDBActiveUser(host, configDir string) (string, bool) {
97		data, err := os.ReadFile(filepath.Join(configDir, "hosts.json"))
98		if err != nil {
99			return "", false
100		}
101		var hosts map[string]*entireAuthHostInfo
102		if err := json.Unmarshal(data, &hosts); err != nil {
103			return "", false
104		}
105		info := hosts[host]
106		if info == nil || info.ActiveUser == "" {
107			return "", false
108		}
109		return info.ActiveUser, true
110	}
111	
112	// getTokenWithRefresh retrieves a token, refreshing it if expired.
113	// On refresh failure, returns the stale token with a nil error rather than
114	// propagating the refresh error silently (issue #7).
115	func getTokenWithRefresh(ctx context.Context, host, username, baseURL string, skipTLS bool) (string, error) {
116		encoded, err := ReadStoredToken(credentialService(host), username)
117		if err != nil {
118			// "Not found" means no credential is configured — not an error.
119			// Only propagate actual storage failures.
120			if isNotFound(err) {
121				return "", nil
122			}
123			return "", err
124		}
125		token, expiresAt := decodeTokenWithExpiration(encoded)
126		if token == "" {
127			return "", nil
128		}
129		if !tokenExpiredOrExpiring(expiresAt) {
130			return token, nil
131		}
132		refreshed, err := refreshAccessToken(ctx, host, username, baseURL, skipTLS)
133		if err != nil {
134			// Issue #7: surface refresh failure explicitly instead of silently reusing stale token.
135			return "", fmt.Errorf("token expired and refresh failed for %s@%s: %w", username, host, err)
136		}
137		return refreshed, nil
138	}
139	
140	func decodeTokenWithExpiration(encoded string) (string, time.Time) {
141		idx := strings.LastIndex(encoded, "|")
142		if idx == -1 {
143			return encoded, time.Time{}
144		}
145		token := encoded[:idx]
146		ts, err := strconv.ParseInt(encoded[idx+1:], 10, 64)
147		if err != nil {
148			return encoded, time.Time{}
149		}
150		return token, time.Unix(ts, 0)
151	}
152	
153	func tokenExpiredOrExpiring(expiresAt time.Time) bool {
154		if expiresAt.IsZero() {
155			return true
156		}
157		return time.Now().Add(5 * time.Minute).After(expiresAt)
158	}
159	
160	func refreshAccessToken(ctx context.Context, host, username, baseURL string, skipTLS bool) (string, error) {
161		refreshToken, err := ReadStoredToken(credentialService(host)+":refresh", username)
162		if err != nil {
163			return "", err
164		}
165		if refreshToken == "" || baseURL == "" {
166			return "", errors.New("missing refresh token or base url")
167		}
168	
169		form := url.Values{}
170		form.Set("grant_type", "refresh_token")
171		form.Set("refresh_token", refreshToken)
172		form.Set("client_id", entireCLIClientID)
173	
174		req, err := http.NewRequestWithContext(ctx, http.MethodPost, strings.TrimRight(baseURL, "/")+"/oauth/token", strings.NewReader(form.Encode()))
175		if err != nil {
176			return "", fmt.Errorf("create token refresh request: %w", err)
177		}
178		req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
179	
180		client := &http.Client{
181			Timeout: 30 * time.Second,
182			Transport: &http.Transport{
183				TLSClientConfig: &tls.Config{InsecureSkipVerify: skipTLS}, //nolint:gosec // InsecureSkipVerify is controlled by user flag
184			},
185		}
186		resp, err := client.Do(req)
187		if err != nil {
188			return "", fmt.Errorf("execute token refresh request: %w", err)
189		}
190		defer resp.Body.Close()
191		if resp.StatusCode != http.StatusOK {
192			return "", fmt.Errorf("refresh failed with status %d", resp.StatusCode)
193		}
194	
195		var tokenResp oauthTokenResponse
196		if err := json.NewDecoder(resp.Body).Decode(&tokenResp); err != nil {
197			return "", fmt.Errorf("decode token refresh response: %w", err)
198		}
199		if tokenResp.AccessToken == "" {
200			return "", errors.New("empty access token in refresh response")
201		}
202	
203		if err := WriteStoredToken(
204			credentialService(host),
205			username,
206			encodeTokenWithExpiration(tokenResp.AccessToken, tokenResp.ExpiresIn),
207		); err != nil {
208			return "", err
209		}
210		if tokenResp.RefreshToken != "" {
211			//nolint:errcheck // best-effort refresh token storage; access token already saved successfully
212			WriteStoredToken(credentialService(host)+":refresh", username, tokenResp.RefreshToken)
213		}
214		return tokenResp.AccessToken, nil
215	}
216	
217	func encodeTokenWithExpiration(token string, expiresIn int64) string {
218		return fmt.Sprintf("%s|%d", token, time.Now().Unix()+expiresIn)
219	}
220	
221	func credentialService(host string) string {
222		return "entire:" + host
223	}
