171	// endpoint. When username/password are set, they are appended (for use with
172	// `git credential approve`/`reject`). When both are empty, the result is a
173	// query body suitable for `git credential fill`. Explicit username overrides
174	// any user embedded in the endpoint URL.
175	func credentialInput(ep *url.URL, username, password string) string {
176		if ep == nil || ep.Hostname() == "" {
177			return ""
178		}
179		var b strings.Builder
180		// gitcredentials(7) defines host as "host[:port]" — use ep.Host, which
181		// keeps any non-default port. ep.Hostname() drops it, which would store
182		// and look up credentials under the default-port entry instead.
183		fmt.Fprintf(&b, "protocol=%s\nhost=%s\n", ep.Scheme, ep.Host)
184		if path := strings.TrimPrefix(ep.Path, "/"); path != "" {
185			fmt.Fprintf(&b, "path=%s\n", path)
186		}
187		user := username
188		if user == "" && ep.User != nil {
189			user = ep.User.Username()
190		}
191		if user != "" {
192			fmt.Fprintf(&b, "username=%s\n", user)
193		}
194		if password != "" {
195			fmt.Fprintf(&b, "password=%s\n", password)
196		}
197		b.WriteString("\n")
198		return b.String()
199	}
200	
201	func parseCredentialOutput(output []byte) map[string]string {
202		values := map[string]string{}
203		for _, line := range strings.Split(string(output), "\n") {
204			line = strings.TrimSpace(line)
205			if line == "" {
206				continue
207			}
208			k, v, ok := strings.Cut(line, "=")
209			if ok {
210				values[k] = v
211			}
212		}
213		return values
214	}
