package main

import (
	"bufio"
	"context"
	"fmt"
	"io"
	"os"
	"os/exec"
	"time"
)

// Probe drives git-remote-entire's stateless-connect for a given service and
// prints the framed advertisement it sends back, so we can confirm the wire
// shape before implementing a transport against it.
func main() {
	url := "entire://aws-us-east-2.entire.io/et/soph-test/soph-test-large-ref"
	if len(os.Args) > 1 {
		url = os.Args[1]
	}
	for _, svc := range []string{"git-upload-pack", "git-receive-pack"} {
		fmt.Printf("\n===== stateless-connect %s =====\n", svc)
		probe(url, svc)
	}
}

func probe(url, service string) {
	ctx, cancel := context.WithTimeout(context.Background(), 20*time.Second)
	defer cancel()

	cmd := exec.CommandContext(ctx, "git-remote-entire", "entire", url)
	stdin, _ := cmd.StdinPipe()
	stdout, _ := cmd.StdoutPipe()
	stderr, _ := cmd.StderrPipe()
	if err := cmd.Start(); err != nil {
		fmt.Println("start:", err)
		return
	}
	go func() { io.Copy(os.Stderr, stderr) }()

	// Send capabilities probe then stateless-connect.
	fmt.Fprintf(stdin, "stateless-connect %s\n\n", service)

	br := bufio.NewReader(stdout)
	// First: the helper's response line (empty line = ok, "fallback", or error).
	done := make(chan struct{})
	go func() {
		defer close(done)
		readFramed(br)
	}()
	select {
	case <-done:
	case <-ctx.Done():
		fmt.Println("[timeout reading advertisement]")
	}
	stdin.Close()
	cmd.Wait()
}

// readFramed reads pkt-lines and prints them until it has seen a flush and a
// response-end, or hits an idle gap (the helper waiting for our request).
func readFramed(br *bufio.Reader) {
	pkts := 0
	for {
		hdr := make([]byte, 4)
		if _, err := io.ReadFull(br, hdr); err != nil {
			fmt.Printf("[read header: %v after %d pkts]\n", err, pkts)
			return
		}
		s := string(hdr)
		if s == "0000" {
			fmt.Println("-- flush (0000) --")
			pkts++
			continue
		}
		if s == "0001" {
			fmt.Println("-- delim (0001) --")
			pkts++
			continue
		}
		if s == "0002" {
			fmt.Println("-- response-end (0002) --")
			return
		}
		var n int
		if _, err := fmt.Sscanf(s, "%04x", &n); err != nil {
			fmt.Printf("[bad length %q: %v]\n", s, err)
			return
		}
		body := make([]byte, n-4)
		if _, err := io.ReadFull(br, body); err != nil {
			fmt.Printf("[read body: %v]\n", err)
			return
		}
		pkts++
		if len(body) > 120 {
			fmt.Printf("[%04d] %q...(%d bytes)\n", n, body[:120], len(body))
		} else {
			fmt.Printf("[%04d] %q\n", n, body)
		}
		if pkts > 60 {
			fmt.Println("[...truncated, stopping]")
			return
		}
	}
}

