1	package githelper
2	
3	import (
4		"bytes"
5		"context"
6		"fmt"
7		"io"
8		"net/http"
9	
10		"github.com/entireio/cli/internal/remotehelper/debuglog"
11		"github.com/entireio/cli/internal/remotehelper/gitproto"
12	)
13	
14	// handleStatelessConnect proxies Git protocol v2 upload-pack. The
15	// remote helper contract is the same shape as git-remote-curl: first
16	// prove the server speaks v2 by fetching info/refs with
17	// Git-Protocol: version=2, then write the server's capability
18	// advertisement and relay each flush-terminated request body as an
19	// independent POST.
20	func handleStatelessConnect(ctx context.Context, t Transport, service string, stdin io.Reader, stdout io.Writer) error {
21		switch service {
22		case serviceUploadPack:
23		case serviceReceivePack:
24			fmt.Fprintln(stdout)
25			return handleConnect(ctx, t, service, stdin, stdout)
26		default:
27			fmt.Fprintln(stdout, "fallback")
28			return nil
29		}
30	
31		refs, err := t.InfoRefsV2(ctx)
32		if err != nil {
33			return fmt.Errorf("stateless-connect v2 info/refs: %w", err)
34		}
35		defer refs.Close()
36	
37		advertisement, err := io.ReadAll(refs)
38		if err != nil {
39			return fmt.Errorf("reading v2 info/refs: %w", err)
40		}
41		if !gitproto.IsV2Advertisement(advertisement) {
42			fmt.Fprintln(stdout, "fallback")
43			return nil
44		}
45	
46		// bundle-uri is left for native git to drive — we don't intercept
47		// the catalogue or inject auth here. If the server advertises
48		// bundle-uri and the user opted in via transfer.bundleURI=true,
49		// they're responsible for configuring credentials for the bundle
50		// host (e.g. via credential.helper / netrc /
51		// http.<url>.extraHeader). Previously we generated a temp config
52		// with a Bearer token in plain text on disk to make this Just
53		// Work; the security trade-off wasn't worth the convenience.
54	
55		fmt.Fprintln(stdout)
56		if _, err := stdout.Write(advertisement); err != nil {
57			return fmt.Errorf("streaming v2 capabilities: %w", err)
58		}
59	
60		for {
61			reqBody, ok, err := gitproto.ReadFlushTerminatedMessage(stdin)
62			if err != nil {
63				return fmt.Errorf("stateless-connect: read request: %w", err)
64			}
65			if !ok {
66				return nil
67			}
68			reqBody, err = gitproto.AppendAgentToV2Request(reqBody, Agent)
69			if err != nil {
70				return fmt.Errorf("stateless-connect: amend agent: %w", err)
71			}
72			command := gitproto.V2Command(reqBody)
73			if command != "" {
74				debuglog.Printf("v2 command: %s", command)
75			}
76	
77			resp, err := t.ServiceRPC(ctx, service, bytes.NewReader(reqBody), func(req *http.Request) {
78				req.Header.Set("Git-Protocol", "version=2")
79			})
80			if err != nil {
81				return fmt.Errorf("stateless-connect: POST: %w", err)
82			}
83	
84			if command == "bundle-uri" {
85				respBody, readErr := io.ReadAll(resp)
86				if readErr != nil {
87					_ = resp.Close()
88					return fmt.Errorf("reading bundle-uri response: %w", readErr)
89				}
90				if err := resp.Close(); err != nil {
91					return fmt.Errorf("closing bundle-uri response: %w", err)
92				}
93				if len(respBody) == 0 {
94					debuglog.Printf("bundle-uri response was empty; synthesizing flush packet")
95					respBody = []byte("0000")
96				}
97				if _, err := stdout.Write(respBody); err != nil {
98					return fmt.Errorf("streaming bundle-uri response: %w", err)
99				}
100			} else {
101				if _, err := io.Copy(stdout, resp); err != nil {
102					_ = resp.Close()
103					return fmt.Errorf("streaming stateless response: %w", err)
104				}
105				if err := resp.Close(); err != nil {
106					return fmt.Errorf("closing stateless response: %w", err)
107				}
108			}
109	
110			if _, err := stdout.Write([]byte("0002")); err != nil {
111				return fmt.Errorf("writing response-end packet: %w", err)
112			}
113		}
114	}
