251		}
252		defer resp.Close()
253	
254		var src io.Reader = resp
255		if stripShallow {
256			src, err = drainShallowUpdate(resp)
257			if err != nil {
258				return fmt.Errorf("draining shallow-update prefix on round %d: %w", roundNumber, err)
259			}
260		}
261	
262		if _, err := io.Copy(stdout, src); err != nil {
263			return fmt.Errorf("streaming round %d response: %w", roundNumber, err)
264		}
265		if !final {
