274	// + the terminating flush from r and returns the trimmed reader. It is
275	// the stream-mirror of fetch-pack.c:205-223 `consume_shallow_list`,
276	// applied to intermediate AND final rounds in our connect-mode bridge
277	// because each have-round POST repeats `deepen` and the server
278	// dutifully re-emits the boundary section.
279	//
280	// If the first pktline isn't shallow/unshallow, returns r untouched —
281	// safe to call defensively on every shallow round even when the
282	// server (e.g. a probe-only response) happens to have no
283	// shallow-update prefix.
284	func drainShallowUpdate(r io.Reader) (io.Reader, error) {
285		br := bufio.NewReader(r)
286		for {
287			l, payload, err := pktline.PeekLine(br)
288			if err != nil {
289				if errors.Is(err, io.EOF) {
290					return br, nil
291				}
292				return nil, fmt.Errorf("peeking shallow-update pktline: %w", err)
293			}
294			if l == pktline.Flush {
295				if _, err := br.Discard(pktline.LenSize); err != nil {
296					return nil, fmt.Errorf("discarding shallow-update flush: %w", err)
297				}
298				return br, nil
299			}
300			if !bytes.HasPrefix(payload, []byte("shallow ")) &&
301				!bytes.HasPrefix(payload, []byte("unshallow ")) {
302				return br, nil
303			}
304			if _, err := br.Discard(l); err != nil {
305				return nil, fmt.Errorf("discarding shallow pktline: %w", err)
306			}
307		}
308	}
