90	func ReadFlushTerminatedMessage(r io.Reader) ([]byte, bool, error) {
91		var buf bytes.Buffer
92		lenBuf := make([]byte, pktline.LenSize)
93		for {
94			n, err := io.ReadFull(r, lenBuf)
95			if err != nil {
96				if errors.Is(err, io.EOF) && n == 0 && buf.Len() == 0 {
97					return nil, false, nil
98				}
99				if errors.Is(err, io.ErrUnexpectedEOF) || (errors.Is(err, io.EOF) && n > 0) {
100					return nil, false, fmt.Errorf("reading pkt-line length: %w", io.ErrUnexpectedEOF)
101				}
102				return nil, false, fmt.Errorf("reading pkt-line length: %w", err)
103			}
104			buf.Write(lenBuf)
105	
106			pktLen, err := pktline.ParseLength(lenBuf)
107			if err != nil {
108				return nil, false, err //nolint:wrapcheck // pktline.ParseLength already returns a typed error
109			}
110			switch pktLen {
111			case pktline.Flush:
112				return buf.Bytes(), true, nil
113			case pktline.Delim, pktline.ResponseEnd:
114				continue
115			}
116			if pktLen < pktline.LenSize {
117				return nil, false, fmt.Errorf("invalid pkt-line length %d", pktLen)
118			}
119	
120			payload := make([]byte, pktLen-pktline.LenSize)
121			if _, err := io.ReadFull(r, payload); err != nil {
122				return nil, false, fmt.Errorf("reading pkt-line content: %w", err)
123			}
124			buf.Write(payload)
125		}
126	}
127	
128	// ReadPostServiceAdvertisement reads a v0/v1 smart-HTTP info/refs body
129	// and returns the bytes that follow the service announcement plus
130	// its terminating flush — i.e. just the ref advertisement.
131	//
132	// `git send-pack --stateless-rpc` runs the input through
133	// discover_version + get_remote_heads, which die with "protocol
134	// error: unexpected '# service=...'" if the announcement preamble is
135	// left in. Strip it once, here, so callers can feed the result
136	// straight into send-pack.
137	func ReadPostServiceAdvertisement(r io.Reader) ([]byte, error) {
138		br := bufio.NewReader(r)
139		var reply packp.SmartReply
140		if err := reply.Decode(br); err != nil {
141			return nil, fmt.Errorf("decoding smart-HTTP service announcement: %w", err)
142		}
143		body, err := io.ReadAll(br)
144		if err != nil {
145			return nil, fmt.Errorf("reading ref advertisement: %w", err)
146		}
147		return body, nil
148	}
149	
150	// ReadReceivePackRequest reads a v0/v1 git-receive-pack request body
151	// from r: a sequence of command pkt-lines terminated by a flush,
152	// optionally followed by a raw PACK stream when at least one command
153	// is not a delete (i.e. the new OID isn't all zeros).
154	//
155	// The returned bytes are exactly what was on the wire — caller
156	// streams them to the remote without further framing. EOF before the
157	// flush is reported (treating it as a clean close would let a
158	// truncated request look like a clean delete-only push).
159	func ReadReceivePackRequest(r io.Reader) ([]byte, error) {
160		var buf bytes.Buffer
161		lenBuf := make([]byte, pktline.LenSize)
162		needPackData := false
163	
164		for {
165			n, err := io.ReadFull(r, lenBuf)
166			if err != nil {
167				if errors.Is(err, io.EOF) && n == 0 && buf.Len() == 0 {
168					return buf.Bytes(), nil
169				}
170				if errors.Is(err, io.ErrUnexpectedEOF) || (errors.Is(err, io.EOF) && n > 0) {
171					return nil, fmt.Errorf("reading pkt-line length: %w", io.ErrUnexpectedEOF)
172				}
173				return nil, fmt.Errorf("reading pkt-line length: %w", err)
174			}
175	
176			pktLen, err := pktline.ParseLength(lenBuf)
177			if err != nil {
178				return nil, fmt.Errorf("receive-pack request: %w", err)
179			}
180			buf.Write(lenBuf)
181	
182			if pktLen == pktline.Flush {
183				if needPackData {
184					if _, err := io.Copy(&buf, r); err != nil {
185						return nil, fmt.Errorf("reading pack data: %w", err)
186					}
187				}
188				return buf.Bytes(), nil
189			}
190			if pktLen < pktline.LenSize {
191				continue
192			}
193	
194			content := make([]byte, pktLen-pktline.LenSize)
195			if _, err := io.ReadFull(r, content); err != nil {
196				return nil, fmt.Errorf("reading pkt-line content: %w", err)
197			}
198			buf.Write(content)
199	
200			if !needPackData && receivePackCommandNeedsPack(content) {
201				needPackData = true
202			}
203		}
204	}
205	
206	// receivePackCommandNeedsPack reports whether a receive-pack command
207	// pkt-line describes a non-delete update (new OID not all zeros).
208	// Wire shape: "<old-id> <new-id> <ref>[\0<capabilities>]\n". Works
209	// for both SHA-1 (40-hex) and SHA-256 (64-hex) object IDs.
210	func receivePackCommandNeedsPack(content []byte) bool {
211		line := content
212		if i := bytes.IndexByte(line, 0); i >= 0 {
213			line = line[:i]
214		} else {
215			line = bytes.TrimSuffix(line, []byte("\n"))
216		}
217		_, rest, ok := bytes.Cut(line, []byte{' '})
218		if !ok {
219			return false
220		}
221		newOID, _, ok := bytes.Cut(rest, []byte{' '})
222		if !ok || len(newOID) == 0 {
223			return false
224		}
225		for _, b := range newOID {
226			if b != '0' {
227				return true
228			}
229		}
230		return false
231	}
232	
233	// ReadSendPackRequest reads one request emitted by
234	// `git send-pack --stateless-rpc` and writes the unwrapped payload to
235	// dst. Send-pack wraps the receive-pack request in an outer pkt-line
236	// stream so it can mark request boundaries without closing stdout;
237	// the HTTP body is the concatenated payload of those outer packets.
238	//
239	// Returns when the outer flush is seen. Special lengths 1/2 are
240	// tolerated and skipped (current send-pack doesn't emit them, but
241	// the shape is permissive). EOF before the flush is wrapped as
