			if errors.Is(err, io.EOF) || errors.Is(err, io.ErrUnexpectedEOF) {
				return nil
			}
			return fmt.Errorf("read request: %w", err)
		}
		io.WriteString(stdout, fakeFetchResponse)
		io.WriteString(stdout, "0002")
		return nil
	case "git-receive-pack":
		io.WriteString(stdout, fakeV0Advertisement)
